import React, { useState } from 'react';
import axios from 'axios';
import { useAuth } from '../../context/AuthContext';

export default function AdminProfile() {
  const { user, setUser } = useAuth();
  const [loading, setLoading] = useState(false);
  const [msg, setMsg] = useState({ type: '', text: '' });
  const [form, setForm] = useState({ name: user?.name || '', email: user?.email || '', phone: user?.phone || '' });
  const [pwForm, setPwForm] = useState({ currentPassword: '', newPassword: '', confirmPassword: '' });
  const [pwSaving, setPwSaving] = useState(false);

  const handleSave = async (e) => {
    e.preventDefault();
    setLoading(true);
    setMsg({ type: '', text: '' });
    try {
      const r = await axios.put('/auth/profile', form);
      // Update local storage and context
      const updatedUser = { ...user, ...r.data.user };
      localStorage.setItem('user', JSON.stringify(updatedUser));
      setUser(updatedUser);
      setMsg({ type: 'success', text: 'Profile updated successfully.' });
    } catch (err) {
      setMsg({ type: 'error', text: err.response?.data?.message || 'Failed to update profile.' });
    } finally {
      setLoading(false);
    }
  };

  const handlePassword = async (e) => {
    e.preventDefault();
    if (pwForm.newPassword !== pwForm.confirmPassword) {
      setMsg({ type: 'error', text: 'New passwords do not match.' });
      return;
    }
    setPwSaving(true);
    setMsg({ type: '', text: '' });
    try {
      await axios.put('/auth/change-password', {
        currentPassword: pwForm.currentPassword,
        newPassword: pwForm.newPassword,
      });
      setPwForm({ currentPassword: '', newPassword: '', confirmPassword: '' });
      setMsg({ type: 'success', text: 'Password updated successfully.' });
    } catch (err) {
      setMsg({ type: 'error', text: err.response?.data?.message || 'Failed to change password.' });
    } finally {
      setPwSaving(false);
    }
  };

  return (
    <div className="animate-fade">
      <div className="page-hero">
        <p className="page-hero-label">Administration Portal</p>
        <h2>Account Settings</h2>
        <p className="page-hero-meta">Manage your administrative profile and security</p>
      </div>

      <div className="profile-header">
        <div className="profile-avatar-lg">{user?.name?.charAt(0).toUpperCase()}</div>
        <div className="profile-info">
          <h1>{user?.name}</h1>
          <p>{user?.email} · Administrator</p>
          <div className="profile-badges" style={{ marginTop: 8 }}>
            <span className="kec-badge">KEC Staff</span>
            <span className="badge badge-admin-reg">Full Access</span>
          </div>
        </div>
      </div>

      {msg.text && <div className={`alert alert-${msg.type === 'success' ? 'success' : 'error'}`}>{msg.text}</div>}

      <div className="profile-grid">
        <div className="card">
          <div className="card-header">
            <h3 className="card-title"><span>👤</span> Personal Information</h3>
          </div>
          <form onSubmit={handleSave}>
            <div className="form-group">
              <label>Full Name</label>
              <input 
                className="input-field" 
                value={form.name} 
                onChange={e => setForm({ ...form, name: e.target.value })} 
                required 
              />
            </div>
            <div className="form-group">
              <label>Email Address</label>
              <input 
                className="input-field" 
                type="email" 
                value={form.email} 
                onChange={e => setForm({ ...form, email: e.target.value })} 
                required 
              />
            </div>
            <div className="form-group">
              <label>Phone Number</label>
              <input 
                className="input-field" 
                value={form.phone} 
                onChange={e => setForm({ ...form, phone: e.target.value })} 
              />
            </div>
            <button type="submit" className="btn btn-primary" disabled={loading}>
              {loading ? 'Saving...' : 'Save Profile Details'}
            </button>
          </form>
        </div>

        <div className="card">
          <div className="card-header">
            <h3 className="card-title"><span>🔒</span> Security & Password</h3>
          </div>
          <form onSubmit={handlePassword}>
            <div className="form-group">
              <label>Current Password</label>
              <input 
                className="input-field" 
                type="password" 
                value={pwForm.currentPassword} 
                onChange={e => setPwForm({ ...pwForm, currentPassword: e.target.value })} 
                required 
              />
            </div>
            <div className="form-row">
              <div className="form-group">
                <label>New Password</label>
                <input 
                  className="input-field" 
                  type="password" 
                  value={pwForm.newPassword} 
                  onChange={e => setPwForm({ ...pwForm, newPassword: e.target.value })} 
                  required 
                  minLength={6} 
                />
              </div>
              <div className="form-group">
                <label>Confirm Password</label>
                <input 
                  className="input-field" 
                  type="password" 
                  value={pwForm.confirmPassword} 
                  onChange={e => setPwForm({ ...pwForm, confirmPassword: e.target.value })} 
                  required 
                />
              </div>
            </div>
            <button type="submit" className="btn btn-outline" disabled={pwSaving}>
              {pwSaving ? 'Updating...' : 'Change Password'}
            </button>
          </form>
        </div>

        <div className="card" style={{ gridColumn: 'span 2' }}>
          <div className="card-header">
            <h3 className="card-title"><span>🛠️</span> System Information</h3>
          </div>
          <div className="info-list" style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 'x 32px' }}>
            <div className="info-row"><span>Authorized Role</span><strong>Administrator</strong></div>
            <div className="info-row"><span>Account Status</span><strong className="text-success">Active</strong></div>
            <div className="info-row"><span>Portal Version</span><strong>v2.1.0</strong></div>
            <div className="info-row"><span>Institution</span><strong>Kongu Engineering College</strong></div>
          </div>
        </div>
      </div>
    </div>
  );
}
